} }}

parameters.jsCode:
// Parse the Groq response and normalise.
// Falls back to 'Unclear' if JSON parse fails - matches the Python pipeline's behaviour.
const input = $input.first().json;
const originalEmail = $('Webhook (Email In)').first().json.body;

let classification;
try {
  const content = input.choices[0].message.content;
  classification = JSON.parse(content);
} catch (e) {
  classification = {
    category: 'Unclear',
    confidence: 0.0,
    reasoning: `Failed to parse model output: ${e.message}`,
    fields: { customer_name: null, contact_number: null, product_or_serial: null, location: null, urgency: 'low' }
  };
}

// Build routing decision
const routes = {
  'Product Enquiry':   { to: 'sales-team@distributor.local',   channel: '#sales-inbox' },
  'Service Request':   { to: 'service-team@distributor.local', channel: '#service-tickets' },
  'Quote Follow-up':   { to: 'sales-team@distributor.local',   channel: '#sales-inbox' },
  'Urgent Escalation': { to: 'ops-alerts@distributor.local',   channel: '#ops-critical' },
  'Unclear':           { to: 'human-review@distributor.local', channel: '#triage-queue' },
};
const target = routes[classification.category] || routes['Unclear'];

const actions = [];
if (classification.category === 'Urgent Escalation') {
  actions.push(`PRIORITY=HIGH alert sent to ${target.to}`);
  actions.push(`Slack ${target.channel} pinged with @oncall`);
} else if (classification.category === 'Unclear') {
  actions.push(`Queued for human review at ${target.to}`);
} else {
  actions.push(`Forwarded to ${target.to} (Slack ${target.channel})`);
}
if (classification.confidence < 0.6 && classification.category !== 'Unclear') {
  actions.push('Low-confidence flag set - secondary review by triage analyst');
}

const needsDraft = ['Product Enquiry', 'Quote Follow-up'].includes(classification.category);

return [{
  json: {
    id: originalEmail.id || 'email_1',
    subject: originalEmail.subject || '',
    body: originalEmail.body,
    classification,
    routing: { destination: target.to, channel: target.channel, actions },
    needs_draft: needsDraft,
    processed_at: new Date().toISOString()
  }
}];

// In production: replace with real Slack webhook node.
const data = $input.first().json;
console.log(`🚨 URGENT ALERT: ${data.subject}`);
console.log(`Routed to: ${data.routing.destination}`);
return [{ json: { ...data, alert_sent: true } }];

